<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }
        
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            font-size: 10pt;
            line-height: 1.4;
            color: #333;
            padding: 20px;
        }
        
        table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 8px;
        }
        
        .letterhead-section {
            margin-bottom: 15px;
            text-align: center;
        }
        
        .document-title {
            text-align: center;
            font-size: 16pt;
            font-weight: bold;
            padding: 12px 0;
            margin: 15px 0;
            border-top: 2px solid #000;
            border-bottom: 2px solid #000;
            text-transform: uppercase;
            letter-spacing: 1px;
        }
        
        .info-section table {
            border: 1px solid #333;
        }
        
        .info-section td {
            padding: 8px 10px;
            border: 1px solid #333;
            vertical-align: top;
            font-size: 9.5pt;
        }
        
        .info-label {
            font-weight: 600;
            color: #000;
        }
        
        .section-header {
            background-color: #e8e8e8;
            font-weight: bold;
            text-align: center;
            padding: 8px;
            border: 1px solid #333;
            font-size: 10pt;
            text-transform: uppercase;
        }
        
        .items-table {
            border: 1px solid #333;
            margin-top: 10px;
            margin-bottom: 10px;
        }
        
        .items-table th {
            background-color: #e8e8e8;
            padding: 8px 6px;
            border: 1px solid #333;
            font-weight: bold;
            text-align: center;
            font-size: 9.5pt;
            vertical-align: middle;
        }
        
        .items-table td {
            padding: 6px 6px;
            border: 1px solid #333;
            font-size: 9.5pt;
            vertical-align: top;
        }
        
        .items-table .total-row {
            background-color: #f5f5f5;
            font-weight: bold;
        }
        
        .totals-section table {
            border: 1px solid #333;
        }
        
        .totals-section td {
            padding: 6px 10px;
            border: 1px solid #333;
            font-size: 9.5pt;
        }
        
        .totals-section .grand-total-row {
            background-color: #e8e8e8;
            font-weight: bold;
        }
        
        .text-left {
            text-align: left;
        }
        
        .text-right {
            text-align: right;
        }
        
        .text-center {
            text-align: center;
        }
        
        .text-bold {
            font-weight: bold;
        }
        
        .footer-section {
            border: 1px solid #333;
            padding: 10px;
            margin-top: 10px;
            font-size: 9pt;
        }
        
        .signature-table {
            margin-top: 20px;
            border: none;
        }
        
        .signature-table td {
            border: none;
            padding: 10px;
            vertical-align: bottom;
        }
        
        .signature-line {
            border-top: 1px solid #333;
            padding-top: 5px;
            margin-top: 60px;
            display: inline-block;
            min-width: 200px;
        }
        
        .computer-note {
            text-align: center;
            margin-top: 20px;
            font-size: 8pt;
            font-style: italic;
            color: #666;
        }
        
        hr {
            border: none;
            border-top: 1px solid #ccc;
            margin: 8px 0;
        }
        
        .address-block {
            margin-top: 6px;
            line-height: 1.5;
        }
        
        .info-row {
            margin-bottom: 6px;
        }
    </style>
</head>
<body>

<!-- Letterhead Section -->
{% if letter_head %}
<div class="letterhead-section">
    {{ letter_head }}
</div>
{% endif %}

<!-- Document Title -->
<div class="document-title">
    {% if doc.is_return == 0 %}
        {{ _("Purchase Invoice") }}
    {% else %}
        {{ _("Purchase Return") }}
    {% endif %}
</div>

<!-- Invoice Reference Details -->
<div class="info-section">
    <table>
        <tr>
            <td style="width: 50%;">
                <div class="info-row">
                    <span class="info-label">{{ _("PI No.") }}:</span> 
