            </td>
            <td class="text-right">
                {{ doc.get_formatted("rounding_adjustment") if doc.rounding_adjustment else "0.00" }}
            </td>
        </tr>
        
        <tr class="grand-total-row">
            <td>
                {% if bd %}
                    {% if bd.custom_ifsc_code %}
                        <span class="info-label">{{ _("IFSC Code") }}:</span> {{ bd.custom_ifsc_code }}
                    {% endif %}
                    {% if bd.branch_code %}
                        &nbsp;&nbsp;&nbsp;<span class="info-label">{{ _("Branch Code") }}:</span> {{ bd.branch_code }}
                    {% endif %}
                {% endif %}
            </td>
            <td class="text-right">
                <span class="info-label">{{ _("Invoice Value") }}:</span>
            </td>
            <td class="text-right">
                {{ doc.get_formatted("rounded_total") if doc.rounded_total else doc.get_formatted("grand_total") }}
            </td>
        </tr>
    </table>
</div>

<!-- Tax Calculation Details (if available) -->
{% if doc.other_charges_calculation %}
<div style="margin: 10px 0; padding: 10px; border: 1px solid #ddd; background-color: #fafafa; font-size: 8pt;">
    {{ doc.other_charges_calculation }}
</div>
{% endif %}

<!-- Terms and Conditions -->
<div class="footer-section">
    <div>
        <span class="info-label">{{ _("Terms and Conditions") }}:</span>
    </div>
    {% if doc.terms %}
        <div style="margin-top: 6px; font-size: 8.5pt; line-height: 1.4; white-space: pre-wrap;">{{ doc.terms }}</div>
    {% endif %}
</div>

<!-- Signature Section -->
<table class="signature-table">
    <tr>
        <td style="width: 50%; text-align: left;">
            {% if doc.owner %}
                <div class="signature-line">
                    {{ frappe.get_fullname(doc.owner) or "" }}<br>
                    <span class="info-label">{{ _("Prepared By") }}</span>
                </div>
            {% endif %}
        </td>
        <td style="width: 50%; text-align: right;">
            {% if doc.docstatus == 1 and doc.modified_by %}
                <div class="signature-line" style="float: right;">
                    {{ frappe.get_fullname(doc.modified_by) or "" }}<br>
                    <span class="info-label">{{ _("Approved By") }}</span>
                </div>
            {% endif %}
        </td>
    </tr>
</table>

<!-- Computer Generated Note -->
<div class="computer-note">
    <strong>{{ _("This is a computer generated invoice, signature not required") }}</strong>
</div>

</body>
</html>

